#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n; scanf("%d",&n);
        long long sum=0;
        for(int i=0;i<n;i++){
            for(int j=0;j<n;j++){
                int x; scanf("%d",&x);
                if(i==j) sum+=x;
                else if(j==n-1-i) sum+=x;
            }
        }
        printf("%lld\n",sum);
    }
    return 0;
}

